/**
 * Removes regeneratable build artifacts from the workspace (safe to re-create).
 * Does NOT touch src/, src-tauri source, config, or docs.
 *
 * Run: npm run clean
 * Dry run: npm run clean -- --dry-run
 */
import { existsSync, readdirSync, rmSync, statSync } from "node:fs";
import { join, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const root = join(dirname(fileURLToPath(import.meta.url)), "..");
const dryRun = process.argv.includes("--dry-run");

/** Paths relative to repo root — all regenerated by documented npm commands. */
const ARTIFACT_PATHS = [
  "node_modules",
  "dist",
  "ui-export",
  "src-tauri/target",
  "src-tauri/gen",
  "synapse-source-small.zip",
  "synapse-ui-export.zip",
  "vs_buildtools.exe",
];

function dirSizeSimple(dir) {
  let total = 0;
  const stack = [dir];
  while (stack.length) {
    const cur = stack.pop();
    let entries;
    try {
      entries = readdirSync(cur, { withFileTypes: true });
    } catch {
      continue;
    }
    for (const ent of entries) {
      const full = join(cur, ent.name);
      if (ent.isDirectory()) stack.push(full);
      else {
        try {
          total += statSync(full).size;
        } catch {
          /* ignore */
        }
      }
    }
  }
  return total;
}

function sizeOf(rel) {
  const full = join(root, rel);
  if (!existsSync(full)) return 0;
  try {
    const st = statSync(full);
    if (st.isFile()) return st.size;
    return dirSizeSimple(full);
  } catch {
    return 0;
  }
}

const fmt = (n) => {
  if (n >= 1024 ** 3) return `${(n / 1024 ** 3).toFixed(2)} GiB`;
  if (n >= 1024 ** 2) return `${(n / 1024 ** 2).toFixed(2)} MiB`;
  return `${(n / 1024).toFixed(2)} KiB`;
};

let freed = 0;
const removed = [];

for (const rel of ARTIFACT_PATHS) {
  const full = join(root, rel);
  if (!existsSync(full)) continue;
  const bytes = sizeOf(rel);
  if (dryRun) {
    console.log(`  would remove  ${rel}  (${fmt(bytes)})`);
    freed += bytes;
    continue;
  }
  try {
    rmSync(full, { recursive: true, force: true });
    console.log(`  removed  ${rel}  (${fmt(bytes)})`);
    removed.push(rel);
    freed += bytes;
  } catch (err) {
    console.warn(`  failed  ${rel}: ${err.message}`);
  }
}

console.log("");
if (dryRun) {
  console.log(`Would free ~${fmt(freed)}. Run: npm run clean`);
} else if (removed.length === 0) {
  console.log("Nothing to clean — workspace already has no listed artifacts.");
} else {
  console.log(`Freed ~${fmt(freed)}. Reinstall/build when needed:`);
  console.log("  npm install");
  console.log("  npm run build          # or npm run tauri:build");
}
